var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와, 나름 필요한 건 다 있네? 여기서 살림이라도 차렸어?","JPN":"へえ、結構色々揃ってるじゃん。ここで生活でも始める気？","ENG":"Wow, you have pretty much everything you need. Did you set up house here?","TWN":"哇，需要的東西都有耶？妳是在這裡成家了嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"뭐래. 북방합의체의 정보를 넘겨주는 조건으로 잠시 머무르고 있을 뿐이거든?","JPN":"違うわよ。北方合意体の情報を渡す条件で、しばらく滞在してるだけ。","ENG":"What are you on about? I'm only staying for a bit in exchange for passing Northern Union intel.","TWN":"妳在說什麼？就只是以提供北方和議會的情報為條件暫時停留而已。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이런 시골에서 오래 머무를 생각은 없어. 마을 주민들과는 서로 이용하고 있을 뿐이야.","JPN":"こんな田舎に長居するつもりはないわ。村人とは、たまたま利害関係が一致しているに過ぎないし。","ENG":"I have no intention of lingering in a backwater village like this. The villagers and I are just using each other.","TWN":"我不想在這種鄉下停留太久，只不過是和村民互相利用而已。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데-. 장군이나 되던 인간이 뭣 때문에 배신을 해?","JPN":"でもさ～将軍までやってたのに何で裏切ったの？","ENG":"Then why would someone who used to be a general betray her side?","TWN":"但是–曾經當過將軍的人為什麼要背叛？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"너, 펠릭스의 말이라면 끔뻑 죽었잖아.","JPN":"あなた、フェリックスの命令なら何でも従ってたじゃない。","ENG":"You used to jump at Felix's every word.","TWN":"如果是緋莉克絲要妳死，妳馬上就去死了吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"<color=#ffd34c>예전</color>의 <color=#ffd34c>나</color>라면 그랬겠지.","JPN":"<color=#ffd34c>昔</color>の<color=#ffd34c>私</color>ならそうだったかもね。","ENG":"If it were the <color=#ffd34c>old</color> <color=#ffd34c>me</color>, maybe.","TWN":"換作是<color=#ffd34c>以前</color>的 <color=#ffd34c>我</color>應該會這樣。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하지만… 지금은 달라.","JPN":"でも……今は違う。","ENG":"But now it is different.","TWN":"但是…現在不一樣。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"믿기지 않겠지만 나도 혼란스럽다고.","JPN":"信じてくれないかもしれないけど、私だって混乱してるんだから。","ENG":"Believe it or not, I am confused too.","TWN":"雖然難以置信，但我也很混亂。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"쟤 갑자기 왜 저래? 뭐 아는 거 있어요?","JPN":"何か変なものでも食べたのかな？　何か知ってますか？","ENG":"Why is she acting like that all of a sudden? Do you know anything?","TWN":"她突然是怎麼了？是知道什麼嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"레, 레노어 언니가 최근 동면 캡슐에서 깨어났다는 이야기는 들었지만.","JPN":"レ、レノアさんがこの前冬眠カプセルから目覚めたという話は聞きました。","ENG":"I-I heard Ms. Lenore only recently woke up from the hibernation capsule.","TWN":"聽說蕾、蕾諾雅姐姐最近剛從冬眠艙甦醒。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"전 기본적으로 합의체 쪽에 가는 일이 드물어서… 얼굴을 본 건 엄청 오랜만이에요.","JPN":"でも私は合意体の方に行くことがあまりないから……顔を合わせたのはすごく久しぶりです。","ENG":"I rarely go to the Northern Union, so it has been ages since I saw her.","TWN":"我基本上很少去和議會那邊…所以真的很久沒見到她了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어라, 저는 이름으로 부르면서 쟤는 왜 언니예요?","JPN":"あれ、何で私は呼び捨てなのにあっちはさん付けなんですか？","ENG":"Oh? You call me by my name, but you call her with honorifics?","TWN":"咦？妳明明叫我名字，但為什麼叫她姐姐？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예, 예니카는 친구잖아요.","JPN":"イ、イェニカは友だちですから。","ENG":"B-because you're my friend.","TWN":"耶、耶妮卡是朋友嘛。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"친구 아니에요…?","JPN":"友だちじゃなかったですか……？","ENG":"Are we not friends...?","TWN":"不是朋友嗎…？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"친구, 친구 맞아요! 그러니까 뚝!!","JPN":"はい、友だち、友だちですよ！　だから泣かないで！！","ENG":"We're friends! We are! So stop crying!!","TWN":"是、是朋友沒錯！所以停！！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"흥, 나도 내 사정 털어놓을 생각은 없어. 어차피 너희도 내 이야기엔 관심 없잖아?","JPN":"ふん、こっちだって、別に事情を察してほしいっていうわけじゃないわ。どうせ私の話に興味なんてないんでしょ？","ENG":"Hmph. I have no intention of spilling my story. You wouldn't care anyway.","TWN":"嗯，我也不打算說出自己的事，反正妳們也沒興趣吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너흴 도운데에는 그만한 이유가 있으니, 의심할 필요 없어.","JPN":"お前たちを助けたのも、ちゃんと理由があるんだから疑わなくていいわよ。","ENG":"I have my reasons for helping you, so there's no need to be suspicious.","TWN":"會幫助妳們是有原因的，所以不用懷疑。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아하. 펠릭스가 우릴 감시하라 했구나?","JPN":"はは～ん、フェリックスが私たちを監視するように命令したんだ？","ENG":"A-ha. Felix told you to keep tabs on us, didn't she?","TWN":"啊哈，看來是緋莉克絲要妳監視我們啊？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그러니까 아니라고!","JPN":"だから違うって！","ENG":"I already told you that I'm out!","TWN":"我說不是！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너흴 도운 건, 내가 본 미래가 불길해서란 말이야!","JPN":"お前たちを助けたのは、私が見た未来が不吉だったからよ！","ENG":"I helped you because the future I saw was bad.","TWN":"我之所以會幫妳們，是因為看到不祥的未來！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"미래…? 오라클인지 뭔지 그거?","JPN":"未来……？　オラクルなんとかってやつ？","ENG":"The future? You mean that Oracle thing?","TWN":"未來…？是神諭還什麼的嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그래. 근시안적인 부분을 제외하면 대부분의 미래가 어둡게 보여.","JPN":"ええ。すぐ先のことを除けば、ほとんどの未来が暗く見えるの。","ENG":"Yes. Aside from short-sighted blind spots, nearly every future looks bleak.","TWN":"沒錯，除了短視的部分之外，大部分的未來看起來都很黯淡。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"딱 한 번. 비슷한 경험을 한 기억이 있지만…….","JPN":"一度だけ、似たような経験をした覚えがあるけど……","ENG":"Only once. I remember a similar case...","TWN":"雖然我只記得有一次類似的經驗……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그건 오라클의 근원인 무녀의 핏줄이 명부신의 영혼을 받아들였기에 가능한 일이었어.","JPN":"その時はオラクルの根源である巫女の血統が、冥府の神の魂を受け入れたからできたのよ。","ENG":"That was possible because the priestess's blood accepted the Nether God's soul, which is the source of Oracle.","TWN":"但那是神諭來源巫女的血脈接收了冥府神的靈魂才可能辦到的事。"},"stage":{"bg":"NANAHARA2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"명부신의 가능성이 산 자의 혼을 가려, 생명의 사념을 듣는 바람의 목소리에 영향을 끼친 거지.","JPN":"生者の魂が冥府の神の可能性に覆われて、命の思念を聞く風の声に影響を及ぼしたのよね。","ENG":"The Nether God's possibility sifted the living souls and affected the voice of wind that hears life's intent.","TWN":"冥府神的可能性會分辨活人的靈魂，對傾聽生命意念的風聲造成影響。"},"stage":{"bg":"NANAHARA2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하지만 지금은 어떤 미래를 보든 똑같아.","JPN":"でも今はどんな未来を見ても同じ。","ENG":"But right now, no matter which future I look at, it is the same.","TWN":"但現在無論看什麼未來都一樣。"},"stage":{"bg":"OMEN_CAMPAMENTO_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"곳곳에서 튀어나온 나무뿌리가 세상을 감싼 뒤, 오롯이 어둠만이 남은 세상…….","JPN":"あちこちから飛び出た木の根が世界を覆い隠し、やがては闇しか存在しない……","ENG":"Roots burst out everywhere and wrap the world, and only darkness remains...","TWN":"四處竄出的樹根包覆後，只剩下黑暗的世界……"},"stage":{"bg":"OMEN_LOTUS_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"내가 본 미래는 전부 그런 결과로 귀결됐어.","JPN":"私が見た未来はすべて、その結果に収束している。","ENG":"Every future I saw ends like that.","TWN":"我看見的未來全都是得出這樣的結果。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"클론에게 받은 기억을 더듬어봐도, 이런 적은 단한번도 없었다고.","JPN":"クローンから受け継いだ記憶をたどってみたけど、こんなことは一度としてなかったわ。","ENG":"Even combing through the memories I got from the clone, there was never anything like this.","TWN":"就算試著回想從複製人那裡得到的記憶，也從來沒有這樣過。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만, 그게 우리를 돕는 거랑 무슨 상관인데?","JPN":"でも、それと私たちを助けることに何の関係があるの？","ENG":"And what does that have to do with helping us?","TWN":"但是那跟幫助我們有什麼關係？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"간단해.","JPN":"簡単よ。","ENG":"Simple.","TWN":"很簡單。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"펠릭스의 부탁을 받고 온 너흴 도와주면 그 여자에게 빚을 안길뿐더러…….","JPN":"フェリックスに頼まれてここに来たお前たちを助けることで、あの女に借りを作れる。","ENG":"If I help you, who came at Felix's request, I saddle her with a debt, and...","TWN":"要是幫助受到緋莉克絲請求而來的妳們，不只是能讓那個女人對我有所虧欠……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"내가 본 미래는 대균열의 뿌리가 챔버를 삼키기 직전까지 네가 저항하는 모습이었거든.","JPN":"それに私が見た未来で、お前は大亀裂の根がチェンバーを飲み込む直前まで抵抗していたわ。","ENG":"In the future I saw, just before the Grand Dimension Crevice's roots swallowed Chamber, you were still resisting.","TWN":"而且我看到的未來，在大峽谷根部吞噬密室之前，妳都在抵抗。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L24_1","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};